class Solution:
    def solveSudoku(self, board):
        def candidates(r, c):
            used = set()
            for k in range(9):
                used.add(board[r][k])
                used.add(board[k][c])
            br, bc = (r // 3) * 3, (c // 3) * 3
            for i in range(br, br + 3):
                for j in range(bc, bc + 3):
                    used.add(board[i][j])
            return [str(d) for d in range(1, 10) if str(d) not in used]

        def solve():
            for r in range(9):
                for c in range(9):
                    if board[r][c] == '.':
                        for v in candidates(r, c):
                            board[r][c] = v
                            if solve():
                                return True
                            board[r][c] = '.'
                        return False
            return True

        solve()

