class Solution:
    def solveSudoku(self, board):
        rows = [set() for _ in range(9)]
        cols = [set() for _ in range(9)]
        box = [set() for _ in range(9)]
        empties = []
        for r in range(9):
            for c in range(9):
                ch = board[r][c]
                if ch == '.':
                    empties.append((r, c))
                else:
                    rows[r].add(ch)
                    cols[c].add(ch)
                    box[(r // 3) * 3 + c // 3].add(ch)

        def bt(i):
            if i == len(empties):
                return True
            r, c = empties[i]
            b = (r // 3) * 3 + c // 3
            for d in '123456789':
                if d not in rows[r] and d not in cols[c] and d not in box[b]:
                    rows[r].add(d)
                    cols[c].add(d)
                    box[b].add(d)
                    board[r][c] = d
                    if bt(i + 1):
                        return True
                    rows[r].discard(d)
                    cols[c].discard(d)
                    box[b].discard(d)
                    board[r][c] = '.'
            return False

        bt(0)

