var solveSudoku = function(board) {
    const rows = Array.from({length: 9}, () => new Set());
    const cols = Array.from({length: 9}, () => new Set());
    const box = Array.from({length: 9}, () => new Set());
    const empties = [];
    for (let r = 0; r < 9; r++) {
        for (let c = 0; c < 9; c++) {
            const ch = board[r][c];
            if (ch === '.') {
                empties.push([r, c]);
            } else {
                rows[r].add(ch);
                cols[c].add(ch);
                box[(Math.floor(r / 3)) * 3 + Math.floor(c / 3)].add(ch);
            }
        }
    }
    function bt(i) {
        if (i === empties.length) return true;
        const [r, c] = empties[i];
        const b = Math.floor(r / 3) * 3 + Math.floor(c / 3);
        for (const d of '123456789') {
            if (!rows[r].has(d) && !cols[c].has(d) && !box[b].has(d)) {
                rows[r].add(d);
                cols[c].add(d);
                box[b].add(d);
                board[r][c] = d;
                if (bt(i + 1)) return true;
                rows[r].delete(d);
                cols[c].delete(d);
                box[b].delete(d);
                board[r][c] = '.';
            }
        }
        return false;
    }
    bt(0);
};
